#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

from pathlib import Path

DEFAULT_IGNORED_DIR_NAMES = {"draft", "archive", "examples"}


def repo_root(start: Path) -> Path:
    current = start.resolve()
    for candidate in (current, *current.parents):
        if (candidate / ".superpowers").exists() or (candidate / "superpowers").exists():
            return candidate
    return current


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def load_ignored_dir_names(spec_root: Path) -> set[str]:
    ignored = set(DEFAULT_IGNORED_DIR_NAMES)
    ignore_file = spec_root / ".adapter-ignore"
    if ignore_file.is_file():
        for line in ignore_file.read_text(encoding="utf-8").splitlines():
            value = line.strip()
            if not value or value.startswith("#"):
                continue
            ignored.add(value)
    return ignored


def is_ignored_directory(path: Path, ignored_dir_names: set[str]) -> bool:
    return path.name in ignored_dir_names or path.name.startswith(".")


def relevant_markdown_files(directory: Path) -> list[Path]:
    return sorted(
        path
        for path in directory.iterdir()
        if path.is_file() and path.suffix == ".md" and path.name != "index.md"
    )


def summary_from_markdown(path: Path) -> str:
    try:
        lines = read_text(path).splitlines()
    except OSError:
        return ""

    title = ""
    summary = ""
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        if not title and stripped.startswith("#"):
            title = stripped.lstrip("#").strip()
            continue
        if stripped.startswith("<!--"):
            continue
        summary = stripped
        break

    if title and summary:
        return f"{title} — {summary}"
    if title:
        return title
    return summary


def has_relevant_content(directory: Path, ignored_dir_names: set[str]) -> bool:
    if relevant_markdown_files(directory):
        return True
    return any(
        has_relevant_content(child, ignored_dir_names)
        for child in directory.iterdir()
        if child.is_dir() and not is_ignored_directory(child, ignored_dir_names)
    )


def relevant_child_directories(directory: Path, ignored_dir_names: set[str]) -> list[Path]:
    return sorted(
        child
        for child in directory.iterdir()
        if child.is_dir()
        and not is_ignored_directory(child, ignored_dir_names)
        and has_relevant_content(child, ignored_dir_names)
    )


def child_directory_summary(directory: Path, ignored_dir_names: set[str]) -> str:
    leaf_files = relevant_markdown_files(directory)
    if leaf_files:
        return summary_from_markdown(leaf_files[0])

    for child in relevant_child_directories(directory, ignored_dir_names):
        summary = child_directory_summary(child, ignored_dir_names)
        if summary:
            return summary

    index_path = directory / "index.md"
    if index_path.is_file():
        return summary_from_markdown(index_path)
    return ""


def is_path_within(root: Path, target: Path) -> bool:
    try:
        target.relative_to(root)
        return True
    except ValueError:
        return False
